function ColorPalette() {
  const rand = () => '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6,'0');
  const [colors, setColors] = React.useState([rand(),rand(),rand(),rand(),rand()]);
  const [locked, setLocked] = React.useState(new Set());

  const generate = () => {
    setColors(prev => prev.map((c,i)=>locked.has(i)?c:rand()));
  };

  const copy = (hex) => {
    navigator.clipboard?.writeText(hex);
    alert('Copied ' + hex);
  };

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <span style={{fontSize:18,fontWeight:700}}>Color Palette</span>
        <button onClick={generate}
          style={{padding:'8px 16px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
          Generate
        </button>
      </div>
      <div style={{flex:1,display:'flex',gap:8,borderRadius:12,overflow:'hidden'}}>
        {colors.map((hex,i)=> (
          <div key={i} onClick={()=>copy(hex)}
            style={{flex:1,background:hex,display:'flex',flexDirection:'column',justifyContent:'flex-end',alignItems:'center',paddingBottom:12,cursor:'pointer',position:'relative'}}>
            <button onClick={(e)=>{e.stopPropagation();setLocked(p=>{const n=new Set(p);n.has(i)?n.delete(i):n.add(i);return n;});}}
              style={{position:'absolute',top:8,background:'rgba(255,255,255,0.9)',border:'none',borderRadius:4,padding:'4px 8px',fontSize:12,cursor:'pointer'}}>
              {locked.has(i)?'🔒':'🔓'}
            </button>
            <span style={{background:'rgba(0,0,0,0.5)',color:'#fff',padding:'4px 10px',borderRadius:6,fontSize:13,fontFamily:'monospace'}}>
              {hex.toUpperCase()}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<ColorPalette/>);
